#include<bits/stdc++.h>
using namespace std;
int g[310][310][310],f[310][310];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int w,l,r;
        scanf("%d%d%d",&w,&l,&r);
        for(int j=l;j<=r;j++)
        {
            g[l][r][j]=w;
        }
    }
    for(int len=1;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            for(int k=l;k<=r;k++)
            {
                g[l][r][k]=max({g[l][r][k],g[l+1][r][k],g[l][r-1][k]});
            }
        }
    }
    for(int len=1;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            for(int k=l;k<r;k++)
            {
                f[l][r]=max(f[l][r],f[l][k]+f[k+1][r]);
            }
            for(int k=l;k<=r;k++)
            {
                f[l][r]=max(f[l][r],f[l][k-1]+g[l][r][k]+f[k+1][r]);
            }
        }
    }
    printf("%d",f[1][n]);
    return 0;
}
